function guardCurrentRequest() {
  return activeRequests()[0] || state.patrolRequests[0] || null;
}

function guardJobFlow(req) {
  const proof = req ? proofForRequest(req.id)[0] : null;
  const stage = req ? guardWorkflowStage(req) : 'accepted';
  const stageIndex = guardWorkflowIndex(stage);
  const stepDone = key => {
    if (!req) return false;
    if (key === 'share_gps') return Boolean(liveGps.online || liveGps.lastUpdate || guardWorkflowEventRows(req).some(row => /shared gps|gps shared|location shared/i.test(`${row.title || ''} ${row.details || ''}`)) || stageIndex >= guardWorkflowIndex('arrived'));
    if (key === 'upload_proof') return Boolean(proof || stageIndex >= guardWorkflowIndex('upload_proof'));
    return stageIndex > guardWorkflowIndex(key) || stage === 'complete' || (key === 'complete' && stage === 'complete');
  };
  const stepCurrent = key => {
    if (!req) return false;
    if (key === 'share_gps') return !stepDone('share_gps') && stage === 'on_way';
    return key === stage;
  };
  const stepTime = key => {
    if (!req) return '';
    if (key === 'accepted') return guardWorkflowEventTime(req, 'accepted') || req.accepted_at || req.assigned_at || req.created_at;
    if (key === 'on_way') return guardWorkflowEventTime(req, 'on_way') || req.accepted_at || req.assigned_at;
    if (key === 'share_gps') return liveGps.lastUpdate || guardWorkflowEventTime(req, 'on_way') || req.accepted_at || req.assigned_at;
    if (key === 'arrived') return guardWorkflowEventTime(req, 'arrived') || req.started_at || (stageIndex >= guardWorkflowIndex('arrived') ? req.updated_at : '');
    if (key === 'checking') return guardWorkflowEventTime(req, 'checking') || (stageIndex >= guardWorkflowIndex('checking') ? req.started_at || req.updated_at : '');
    if (key === 'upload_proof') return proof?.created_at || proof?.uploaded_at || guardWorkflowEventTime(req, 'upload_proof');
    if (key === 'complete') return req.completed_at || guardWorkflowEventTime(req, 'complete');
    return '';
  };
  const steps = req ? [
    ['accepted', 'Accepted', '✓'],
    ['on_way', 'On The Way', '➜'],
    ['share_gps', 'Share GPS', '⌖'],
    ['arrived', 'Arrived', '⌾'],
    ['checking', 'Checking', '◫'],
    ['upload_proof', 'Upload Proof', '⬆'],
    ['complete', 'Complete', '✓']
  ] : [];
  return `<section class="panel panel-pad guard-flow-panel">
    <div class="panel-head"><div><h2>Job Flow</h2><p>Field workflow status</p></div></div>
    ${steps.length ? `<div class="guard-flow">
      ${steps.map(([key,label,icon]) => {
        const done = stepDone(key);
        const current = stepCurrent(key);
        return `<div class="guard-step ${done ? 'done' : current ? 'current' : 'wait'}"><i>${esc(icon)}</i><strong>${esc(label)}</strong><small>${esc(fmtTime(stepTime(key)))}</small></div>`;
      }).join('')}
    </div>
    <div class="guard-flow-footer"><span><i></i>Status: ${esc(guardWorkflowStageText(stage))}</span><small>Updated ${esc(timeAgo(req.updated_at || guardWorkflowEventTime(req, stage) || req.created_at))}</small></div>` : `<div class="empty">No active workflow yet.</div>`}
  </section>`;
}

