function clientReportValidDate(...values) {
  for (const value of values) {
    if (!value) continue;
    const d = new Date(value);
    if (!isNaN(d.getTime())) return value;
  }
  return '';
}
function clientReportPublishedAt(row = {}) {
  return clientReportValidDate(row.publishedAt, row.releasedAt, row.createdAt, row.report?.released_at, row.report?.published_at, row.report?.publishedAt, row.report?.updated_at, row.report?.created_at, row.req?.completed_at, row.req?.updated_at, row.req?.created_at);
}
function clientReportPatrolAt(row = {}) {
  const req = row.req || requestById(row.requestId) || {};
  return clientReportValidDate(row.patrolAt, req.completed_at, req.ended_at, req.started_at, req.accepted_at, req.scheduled_for, req.created_at, row.createdAt);
}
function clientReportArchiveRows() {
  if (typeof reportArchiveRows !== 'function') return [];
  try {
    return reportArchiveRows()
      .filter(row => {
        const status = typeof reportArchiveStatus === 'function' ? reportArchiveStatus(row) : String(row.status || row.report?.status || '').toLowerCase();
        return status === 'published' || Boolean(row.report?.released_at || row.report?.published_at || row.report?.publishedAt || row.publishedAt);
      })
      .map(row => {
        const req = row.request || {};
        const property = row.property || propertyById(req.property_id || row.report?.property_id) || {};
        const report = row.report || {};
        const publishedAt = clientReportValidDate(row.publishedAt, report.released_at, report.published_at, report.publishedAt, report.updated_at, report.created_at, req.completed_at, req.updated_at, req.created_at);
        const patrolAt = clientReportValidDate(req.completed_at, req.ended_at, req.started_at, req.accepted_at, req.scheduled_for, req.created_at, publishedAt);
        return {
          id: row.id || report.id || `archive-${row.reportNumber || row.request?.id || Math.random()}`,
          report,
          archiveRow: row,
          req,
          reportNumber: row.reportNumber || report.report_number || report.reference_id || `RPT-${String(row.id || req.id || '').slice(0, 8)}`,
          title: row.title || report.title || `${propertyDisplayName(property)} Patrol Report`,
          description: row.summary || report.summary || report.final_summary || report.final_notes || report.notes || req.instructions || 'Released patrol report.',
          status: 'completed',
          createdAt: publishedAt,
          publishedAt,
          patrolAt,
          propertyId: property.id || req.property_id || report.property_id || '',
          propertyName: propertyDisplayName(property),
          propertyAddress: propertyDisplayAddress(property),
          type: req.patrol_type || req.request_type || report.patrol_type || report.type || row.template || 'Patrol',
          guardName: row.guard ? guardDisplayName(row.guard) : (req ? requestGuardName(req) : report.guard_name || 'Unassigned'),
          requestId: req.id || report.request_id || report.patrol_request_id || '',
          proofCount: Number(row.photoCount || 0) + Number(row.videoCount || 0) || (req.id ? proofForRequest(req.id).length : 0),
          proofRows: row.proofRows || [],
          propertyImageUrl: propertyImageValue(property),
          url: report.public_url || report.file_url || report.url || report.pdf_url || '',
          source: 'reportArchive'
        };
      });
  } catch (err) {
    console.warn('Client report archive sync skipped:', err);
    return [];
  }
}
function clientReportSourceRows() {
  const fromArchive = clientReportArchiveRows();
  const archiveRequestIds = new Set(fromArchive.map(row => String(row.requestId || '')).filter(Boolean));
  const archiveReportIds = new Set(fromArchive.map(row => String(row.report?.id || row.id || '')).filter(Boolean));

  const fromReports = (state.patrolReports || [])
    .filter(report => !archiveReportIds.has(String(report.id || '')) && !archiveRequestIds.has(String(report.request_id || report.patrol_request_id || '')))
    .map(report => {
      const req = report.request_id ? requestById(report.request_id) : requestById(report.patrol_request_id);
      const publishedAt = clientReportValidDate(report.released_at, report.published_at, report.publishedAt, report.updated_at, report.created_at, req?.completed_at, req?.updated_at, req?.created_at);
      const patrolAt = clientReportValidDate(req?.completed_at, req?.ended_at, req?.started_at, req?.accepted_at, req?.scheduled_for, req?.created_at, publishedAt);
      return {
        id: report.id || `report-${report.request_id || report.patrol_request_id || Math.random()}`,
        report,
        req,
        reportNumber: report.report_number || report.reference_id || `RPT-${String(report.id || report.request_id || '').slice(0, 8)}`,
        title: report.title || report.name || (req ? `${propertyLabel(req)} Patrol Report` : 'Patrol Report'),
        description: report.summary || report.notes || report.final_notes || report.details || (req?.instructions || 'Released patrol report.'),
        status: report.status || (report.released_at || report.published_at || report.publishedAt ? 'completed' : 'pending_review'),
        createdAt: publishedAt,
        publishedAt,
        patrolAt,
        propertyId: req?.property_id || report.property_id || '',
        propertyName: req ? propertyLabel(req) : report.property_name || 'Property',
        propertyAddress: req ? propertyAddress(req) : report.property_address || '',
        type: req?.patrol_type || req?.request_type || report.patrol_type || report.type || 'Patrol',
        guardName: req ? requestGuardName(req) : report.guard_name || 'Unassigned',
        requestId: report.request_id || report.patrol_request_id || req?.id || '',
        proofCount: report.proof_count || (req ? proofForRequest(req.id).length : 0),
        proofRows: req ? proofForRequest(req.id) : [],
        propertyImageUrl: req ? getPropertyPhotoUrl(req) : propertyImageValue(propertyById(report.property_id)),
        url: report.public_url || report.file_url || report.url || report.pdf_url || '',
        source: 'patrolReports'
      };
    });

  const reportReqIds = new Set([...archiveRequestIds, ...fromReports.map(row => String(row.requestId || '')).filter(Boolean)]);
  const fromCompleted = completedRequests()
    .filter(req => !reportReqIds.has(String(req.id)))
    .map(req => {
      const publishedAt = clientReportValidDate(req.released_at, req.published_at, req.completed_at, req.updated_at, req.created_at);
      return {
        id: `completed-${req.id}`,
        report: null,
        req,
        reportNumber: `RPT-${String(req.id || '').slice(0, 8)}`,
        title: `${propertyLabel(req)} Final Patrol Report`,
        description: req.instructions || 'Completed patrol report ready for review.',
        status: 'completed',
        createdAt: publishedAt,
        publishedAt,
        patrolAt: clientReportValidDate(req.completed_at, req.ended_at, req.started_at, req.accepted_at, req.scheduled_for, req.created_at),
        propertyId: req.property_id || '',
        propertyName: propertyLabel(req),
        propertyAddress: propertyAddress(req),
        type: req.patrol_type || req.request_type || req.schedule_type || 'Patrol',
        guardName: requestGuardName(req),
        requestId: req.id,
        proofCount: proofForRequest(req.id).length,
        proofRows: proofForRequest(req.id),
        propertyImageUrl: getPropertyPhotoUrl(req),
        url: '',
        source: 'completedRequests'
      };
    });

  const seen = new Set();
  return [...fromArchive, ...fromReports, ...fromCompleted]
    .filter(row => {
      const key = String(row.report?.id || row.requestId || row.id || row.reportNumber || Math.random());
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .sort((a,b) => new Date(clientReportPublishedAt(b) || 0) - new Date(clientReportPublishedAt(a) || 0));
}
function clientReportTypeLabel(value = '') {
  const v = String(value || '').toLowerCase();
  if (v.includes('immediate')) return 'Immediate Patrol';
  if (v.includes('vacation')) return 'Vacation Watch';
  if (v.includes('recurring')) return 'Recurring Patrol';
  if (v.includes('scheduled')) return 'Scheduled Patrol';
  return statusText(value || 'Patrol');
}
function clientReportTypeIcon(value = '') {
  const label = clientReportTypeLabel(value).toLowerCase();
  if (label.includes('immediate')) return 'ϟ';
  if (label.includes('vacation')) return '▣';
  if (label.includes('recurring')) return '↻';
  if (label.includes('scheduled')) return '▦';
  return '▤';
}
function clientReportStatus(row = {}) {
  const raw = String(row.status || '').toLowerCase();
  if (raw.includes('attention') || raw.includes('incident') || raw.includes('flag')) return 'attention';
  if (raw.includes('pending') || raw.includes('review')) return 'pending_review';
  if (raw.includes('progress')) return 'in_progress';
  if (raw.includes('complete') || raw.includes('released') || raw.includes('approved')) return 'completed';
  return 'completed';
}
function clientReportStatusLabel(status = '') {
  if (status === 'pending_review') return 'Pending Review';
  if (status === 'in_progress') return 'In Progress';
  if (status === 'attention') return 'Attention';
  return 'Published Report';
}
function filteredClientReports() {
  let rows = clientReportSourceRows();
  const q = String(state.clientReportSearch || '').trim().toLowerCase();
  if (q) rows = rows.filter(row => [row.reportNumber, row.title, row.description, row.propertyName, row.propertyAddress, row.guardName, clientReportTypeLabel(row.type)].join(' ').toLowerCase().includes(q));
  if (state.clientReportStatusFilter && state.clientReportStatusFilter !== 'all') rows = rows.filter(row => clientReportStatus(row) === state.clientReportStatusFilter);
  if (state.clientReportPropertyFilter && state.clientReportPropertyFilter !== 'all') rows = rows.filter(row => String(row.propertyId) === String(state.clientReportPropertyFilter));
  return rows;
}
function clientReportCounts() {
  const rows = clientReportSourceRows();
  const total = rows.length;
  const completed = rows.filter(row => clientReportStatus(row) === 'completed').length;
  const pending = rows.filter(row => clientReportStatus(row) === 'pending_review').length;
  const attention = rows.filter(row => clientReportStatus(row) === 'attention').length;
  const reportsWithProof = rows.filter(row => (Number(row.proofCount || 0) || clientReportProofRows(row).length) > 0).length;
  const reportsWithoutProof = Math.max(0, rows.length - reportsWithProof);
  const now = new Date();
  const startMonth = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
  const thisMonth = rows.filter(row => new Date(clientReportPublishedAt(row) || row.createdAt || 0).getTime() >= startMonth).length;
  return { total, completed, pending, attention, thisMonth, reportsWithProof, reportsWithoutProof };
}
function clientReportKpi(icon, label, value, sub, tone = 'blue') {
  return `<article class="client-report-kpi ${esc(tone)}"><div class="icon">${esc(icon)}</div><div><span>${esc(label)}</span><strong>${esc(value)}</strong><small>${esc(sub)}</small></div></article>`;
}
function clientReportPropertyOptions() {
  const rows = clientReportSourceRows();
  const ids = new Set(rows.map(r => String(r.propertyId || '')).filter(Boolean));
  const props = (state.properties || []).filter(p => ids.has(String(p.id)));
  return `<option value="all">All Properties</option>${props.map(p => `<option value="${esc(p.id)}" ${String(state.clientReportPropertyFilter) === String(p.id) ? 'selected' : ''}>${esc(propertyDisplayName(p))}</option>`).join('')}`;
}
function clientReportStatusChip(row = {}) {
  const status = clientReportStatus(row);
  return `<span class="report-status-chip ${esc(status)}">${esc(clientReportStatusLabel(status))}</span>`;
}
function clientReportImage(row = {}) {
  const p = propertyById(row.propertyId);
  const img = propertyImageValue(p);
  if (img) return `<img src="${esc(img)}" alt="${esc(row.propertyName)}">`;
  return `<span>${esc(initials(row.propertyName || 'Report'))}</span>`;
}
function clientReportOfficerAvatar(row = {}) {
  const guard = state.guards.find(g => (g.name || g.display_name || g.email) === row.guardName) || {};
  const img = guard.photo_url || guard.avatar_url || guard.profile_photo_url || '';
  if (img) return `<img src="${esc(img)}" alt="${esc(row.guardName)}">`;
  return `<span>${esc(initials(row.guardName || 'G'))}</span>`;
}
function clientReportById(id) {
  return clientReportSourceRows().find(row => String(row.id) === String(id)) || null;
}
function selectedClientReport() {
  const rows = clientReportSourceRows();
  let row = rows.find(item => String(item.id) === String(state.selectedClientReportId || '')) || null;
  if (!row && state.selectedClientReportId) state.selectedClientReportId = '';
  return row;
}
function clientReportProofRows(row = {}) {
  if (!row?.requestId) return [];
  return proofForRequest(row.requestId);
}
function clientReportSafeFileName(value = 'client-report') {
  return String(value || 'client-report').replace(/[^a-z0-9-_]+/gi, '_').replace(/^_+|_+$/g, '') || 'client-report';
}
function clientReportSummaryText(row = {}) {
  const req = row.req || requestById(row.requestId) || {};
  const report = row.report || {};
  return report.summary || report.final_summary || report.final_notes || report.notes || row.description || req.final_summary || req.summary || req.instructions || 'Completed patrol report ready for client review.';
}
function clientReportDownloadText(row = {}) {
  const proofRows = clientReportProofRows(row);
  const req = row.req || requestById(row.requestId) || {};
  return [
    'Co Pilot Security - Client Patrol Report',
    `Report ID: ${row.reportNumber || 'Report'}`,
    `Status: ${clientReportStatusLabel(clientReportStatus(row))}`,
    `Property: ${row.propertyName || 'Property'}`,
    `Address: ${row.propertyAddress || 'Address unavailable'}`,
    `Patrol Type: ${clientReportTypeLabel(row.type)}`,
    `Guard / Officer: ${row.guardName || 'Unassigned'}`,
    `Published On: ${fmtDateTimeStamp(clientReportPublishedAt(row))}`,
    `Patrol Time: ${fmtDateTimeStamp(clientReportPatrolAt(row))}`,
    `Duration: ${typeof reportRequestDuration === 'function' ? reportRequestDuration(req) : '60 min'}`,
    `Proof Items: ${proofRows.length || row.proofCount || 0}`,
    '',
    'Summary:',
    clientReportSummaryText(row),
    '',
    'Client-facing report generated by Co Pilot Security.'
  ].join('\n');
}
function downloadClientReportFile(id) {
  const row = clientReportById(id) || selectedClientReport();
  if (!row) {
    toast('Select a report first.', 'error');
    return;
  }
  if (state.role === 'client' && row.requestId) recordJobAuditEvent(row.requestId, 'client_downloaded', 'Client downloaded report', row.reportNumber || row.title || 'Client report downloaded', { actor: activeClientName(), role: 'client', source: 'client-reports', report_id: row.id, key: `client-downloaded-${row.id}-${Date.now()}` });
  if (row.url) {
    const a = document.createElement('a');
    a.href = row.url;
    a.download = `${clientReportSafeFileName(row.reportNumber)}.pdf`;
    a.target = '_blank';
    a.rel = 'noopener';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => a.remove(), 250);
    toast('Report download opened.', 'success');
    return;
  }
  const blob = new Blob([clientReportDownloadText(row)], { type: 'text/plain;charset=utf-8;' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `${clientReportSafeFileName(row.reportNumber)}.txt`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 500);
  toast('Report downloaded.', 'success');
}
function exportClientReportsCsv() {
  const rows = filteredClientReports();
  const cols = ['reportNumber','property','address','type','publishedOn','patrolTime','status','officer','proofItems','summary'];
  const csv = [cols.join(',')].concat(rows.map(row => [
    row.reportNumber,
    row.propertyName,
    row.propertyAddress,
    clientReportTypeLabel(row.type),
    fmtDateTimeStamp(clientReportPublishedAt(row)),
    fmtDateTimeStamp(clientReportPatrolAt(row)),
    clientReportStatusLabel(clientReportStatus(row)),
    row.guardName,
    row.proofCount || clientReportProofRows(row).length || 0,
    clientReportSummaryText(row)
  ].map(value => `"${String(value ?? '').replace(/"/g, '""')}"`).join(','))).join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `client_reports_${new Date().toISOString().slice(0,10)}.csv`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 500);
}
function clientReportPreviewPanel() {
  const row = selectedClientReport();
  if (!row) {
    return `<section class="panel panel-pad client-report-preview-card empty-preview"><div class="panel-head"><div><h2>Report Preview</h2><p>Select the eye button on any report to preview it here.</p></div></div><div class="client-report-preview-empty">No report selected.</div></section>`;
  }
  const proofRows = clientReportProofRows(row);
  const req = row.req || requestById(row.requestId) || {};
  return `<section class="panel panel-pad client-report-preview-card">
    <div class="client-report-preview-head"><div><span>Selected Report</span><h2>${esc(row.reportNumber)}</h2><p>${esc(row.title || 'Client Patrol Report')}</p></div><button type="button" data-action="clear-selected-client-report">×</button></div>
    <div class="client-report-preview-hero"><div class="preview-report-image">${clientReportImage(row)}</div><div><strong>${esc(row.propertyName)}</strong><small>${esc(row.propertyAddress || 'Address unavailable')}</small>${clientReportStatusChip(row)}</div></div>
    <dl class="client-report-preview-list">
      <dt>Patrol Type</dt><dd>${esc(clientReportTypeLabel(row.type))}</dd>
      <dt>Published On</dt><dd>${esc(fmtDateTimeStamp(clientReportPublishedAt(row)))}</dd>
      <dt>Patrol Time</dt><dd>${esc(fmtDateTimeStamp(clientReportPatrolAt(row)))}</dd>
      <dt>Officer</dt><dd>${esc(row.guardName || 'Unassigned')}</dd>
      <dt>Duration</dt><dd>${esc(typeof reportRequestDuration === 'function' ? reportRequestDuration(req) : '60 min')}</dd>
      <dt>Proof Items</dt><dd>${esc(proofRows.length || row.proofCount || 0)}</dd>
      <dt>Request</dt><dd>${esc(row.requestId ? requestTitle(req) : 'Linked report')}</dd>
    </dl>
    <section class="client-report-preview-summary"><h3>Summary</h3><p>${esc(clientReportSummaryText(row))}</p></section>
    ${proofRows.length ? `<section class="client-report-preview-summary"><h3>Included Proof</h3><p>${esc(proofRows.length)} proof item${proofRows.length === 1 ? '' : 's'} attached to this patrol.</p></section>` : `<section class="client-report-preview-summary"><h3>Included Proof</h3><p>No proof was attached to this report.</p></section>`}
    ${jobTimelinePanel(req, { compact: true, title: 'Report Timeline / Audit Trail', limit: 7 })}
    <div class="client-report-preview-actions"><button type="button" class="primary-button" data-action="download-client-report" data-report-id="${esc(row.id)}">⇩ Download Report</button><button type="button" class="ghost-button" data-view="properties">View Property</button></div>
  </section>`;
}
function clientReportRow(row = {}) {
  const selected = String(state.selectedClientReportId || '') === String(row.id);
  return `<div class="client-report-row ${selected ? 'selected' : ''}">
    <div class="report-main"><div class="report-thumb">${clientReportImage(row)}</div><div><strong>${esc(row.reportNumber)}</strong><small>${esc(row.description)}</small></div></div>
    <div class="report-property"><strong>${esc(row.propertyName)}</strong><small>${esc(row.propertyAddress || 'Address unavailable')}</small></div>
    <div class="report-type"><i>${esc(clientReportTypeIcon(row.type))}</i><span>${esc(clientReportTypeLabel(row.type))}</span></div>
    <div class="report-date"><strong>${esc(fmtDate(clientReportPublishedAt(row)))}</strong><small>Published ${esc(fmtTime(clientReportPublishedAt(row)))}</small><small>Patrol ${esc(fmtTime(clientReportPatrolAt(row)))}</small></div>
    <div>${clientReportStatusChip(row)}</div>
    <div class="report-officer"><div>${clientReportOfficerAvatar(row)}</div><span>${esc(row.guardName)}</span></div>
    <div class="report-actions"><button type="button" data-action="view-client-report" data-report-id="${esc(row.id)}" title="View report">⊙</button><button type="button" data-action="download-client-report" data-report-id="${esc(row.id)}" title="Download report">⇩</button></div>
  </div>`;
}
function clientReportSummaryCard() {
  const counts = clientReportCounts();
  const total = counts.total || 1;
  const completedPct = Math.round((counts.completed / total) * 100);
  const pendingPct = Math.round((counts.pending / total) * 100);
  const attentionPct = Math.round((counts.attention / total) * 100);
  return `<section class="panel panel-pad report-summary-card"><div class="panel-head"><div><h2>Report Summary</h2></div></div><div class="report-donut-wrap"><div class="report-donut" style="--completed:${completedPct};--pending:${pendingPct};--attention:${attentionPct};"></div><div class="report-donut-legend"><span><i class="green"></i>Published <b>${completedPct}% (${counts.completed})</b></span><span><i class="yellow"></i>Pending Review <b>${pendingPct}% (${counts.pending})</b></span><span><i class="red"></i>Attention <b>${attentionPct}% (${counts.attention})</b></span></div></div></section>`;
}
function clientReportActivityCard() {
  const rows = clientReportSourceRows().slice(0, 3);
  return `<section class="panel panel-pad report-activity-card"><div class="panel-head"><div><h2>Recent Activity</h2></div></div><div class="report-activity-list">${rows.length ? rows.map(row => `<div><i class="${esc(clientReportStatus(row))}"></i><span><strong>${esc(row.reportNumber)}</strong><small>${esc(clientReportStatusLabel(clientReportStatus(row)))} • published ${esc(timeAgo(clientReportPublishedAt(row)))}</small></span></div>`).join('') : '<div class="empty">No recent report activity.</div>'}</div><button class="ghost-button wide" type="button" data-action="view-all-report-activity">View All Activity</button></section>`;
}
function clientReportTopPropertiesCard() {
  const map = new Map();
  clientReportSourceRows().forEach(row => {
    const key = row.propertyName || 'Property';
    map.set(key, (map.get(key) || 0) + 1);
  });
  const rows = [...map.entries()].sort((a,b) => b[1]-a[1]).slice(0,5);
  const max = Math.max(1, ...rows.map(r => r[1]));
  return `<section class="panel panel-pad report-top-properties-card"><div class="panel-head"><div><h2>Top Properties</h2></div></div><div class="report-property-bars">${rows.length ? rows.map(([name,count]) => `<div><span>${esc(name)}</span><b><i style="width:${Math.max(10, Math.round((count/max)*100))}%"></i></b><em>${esc(count)}</em></div>`).join('') : '<div class="empty">No property report totals yet.</div>'}</div><button class="ghost-button wide" type="button" data-view="properties">View All Properties</button></section>`;
}
function clientReportsView() {
  const counts = clientReportCounts();
  const rows = filteredClientReports();
  const pageSize = Number(state.clientReportPerPage || 10);
  const page = Math.max(1, Math.min(state.clientReportPage || 1, Math.max(1, Math.ceil(rows.length / pageSize))));
  state.clientReportPage = page;
  const pageRows = rows.slice((page - 1) * pageSize, page * pageSize);
  const completedPct = counts.total ? Math.round((counts.completed / counts.total) * 100) : 0;
  const pendingPct = counts.total ? Math.round((counts.pending / counts.total) * 100) : 0;
  const attentionPct = counts.total ? Math.round((counts.attention / counts.total) * 100) : 0;
  return `<div class="dashboard client-reports-shell">
    <header class="dashboard-header"><div class="title-block"><h1>Reports</h1><p>View and manage all security reports generated from patrols and activity.</p></div><div class="header-actions"><span class="system-pill"><i></i>System Operational</span><button class="header-button">?</button></div></header>
    ${workflowStageLegend('published')}
    <section class="client-report-kpi-row">
      ${clientReportKpi('▤','Total Reports',counts.total,'Matches Dispatch Archive','blue')}
      ${clientReportKpi('✓','Published Reports',counts.completed,`${completedPct}% released`,'green')}
      ${clientReportKpi('🖼','Reports With Proof',counts.reportsWithProof,'Includes photo/video proof','cyan')}
      ${clientReportKpi('Ø','Reports No Proof',counts.reportsWithoutProof,'Published without media','purple')}
      ${clientReportKpi('▣','This Month',counts.thisMonth,'Released this month','orange')}
    </section>
    <section class="client-reports-layout">
      <main class="client-reports-main panel">
        <div class="client-report-toolbar">
          <div class="client-report-search"><span>⌕</span><input type="search" placeholder="Search reports..." value="${esc(state.clientReportSearch)}" data-client-report-search></div>
          <select data-client-report-property-filter>${clientReportPropertyOptions()}</select>
          <select data-client-report-status-filter><option value="all">All Statuses</option><option value="completed" ${state.clientReportStatusFilter === 'completed' ? 'selected' : ''}>Published Report</option><option value="pending_review" ${state.clientReportStatusFilter === 'pending_review' ? 'selected' : ''}>Pending Review</option><option value="attention" ${state.clientReportStatusFilter === 'attention' ? 'selected' : ''}>Attention</option><option value="in_progress" ${state.clientReportStatusFilter === 'in_progress' ? 'selected' : ''}>In Progress</option></select>
          <button type="button" class="ghost-button report-date-range">▣ This Month</button>
          <button type="button" class="primary-button" data-action="export-client-reports">⇩ Export</button>
        </div>
        <div class="client-report-table">
          <div class="client-report-head"><span>Report</span><span>Property</span><span>Type</span><span>Published On</span><span>Status</span><span>Officer</span><span>Actions</span></div>
          ${pageRows.length ? pageRows.map(clientReportRow).join('') : '<div class="empty">No reports match your filters.</div>'}
        </div>
        <footer class="client-report-footer"><span>${esc(rows.length)} total reports — showing ${rows.length ? `${(page - 1) * pageSize + 1} to ${Math.min(page * pageSize, rows.length)}` : '0'} on this page</span><div class="report-pagination"><button type="button" data-action="client-report-page-prev">‹</button><strong>Page ${esc(page)} of ${esc(Math.max(1, Math.ceil(rows.length / pageSize)))}</strong><button type="button" data-action="client-report-page-next">›</button></div><label>Rows per page:<select data-client-report-per-page><option value="8" ${pageSize === 8 ? 'selected' : ''}>8</option><option value="10" ${pageSize === 10 ? 'selected' : ''}>10</option><option value="25" ${pageSize === 25 ? 'selected' : ''}>25</option></select></label></footer>
      </main>
      <aside class="client-reports-rail">
        ${clientReportPreviewPanel()}
        ${clientReportSummaryCard()}
        ${clientReportActivityCard()}
        ${clientReportTopPropertiesCard()}
      </aside>
    </section>
  </div>`;
}


function dispatchBoardKpi(icon, label, value, subtext, tone = 'blue', progress = null) {
  return `<article class="dispatch-board-kpi ${esc(tone)}">
    <div class="dispatch-kpi-icon">${esc(icon)}</div>
    <div class="dispatch-kpi-copy"><span>${esc(label)}</span><strong>${esc(value)}</strong><small>${esc(subtext)}</small></div>
    ${progress !== null ? `<div class="dispatch-kpi-ring" style="--progress:${esc(progress)}"><b>${esc(progress)}%</b></div>` : ''}
  </article>`;
}
function dispatchBoardKpis() {
  const pending = pendingRequests();
  const guards = dispatchMapOnlineGuards();
  const totalGuards = Math.max(1, adminAssignableGuards().length || guards.length || 1);
  const active = activeRequests();
  const approvals = guardApprovals();
  const reports = reportsReady();
  const guardPct = Math.round((guards.length / totalGuards) * 100);
  const activePct = Math.min(100, Math.round((active.length / Math.max(1, state.patrolRequests.length || active.length || 1)) * 100));
  return `<section class="dispatch-board-kpi-row">
    ${dispatchBoardKpi('⏳', 'Pending Dispatch', pending.length, `${pending.filter(r => /high|urgent|emergency/i.test(String(r.priority || ''))).length} urgent • ${pending.length} total`, 'amber')}
    ${dispatchBoardKpi('♙', 'Online Guards', guards.length, `of ${totalGuards} total`, 'green', guardPct)}
    ${dispatchBoardKpi('🛡', 'Active Patrols', active.length, `${active.filter(r => /accepted|assigned/i.test(String(r.status || ''))).length} en route • ${active.filter(r => /in_progress/i.test(String(r.status || ''))).length} on site`, 'blue', activePct)}
    ${dispatchBoardKpi('☑', 'Guard Approvals', approvals.length, 'Pending review', 'purple')}
    ${dispatchBoardKpi('▣', 'Reports Ready', reports.length, 'Ready to view', 'violet')}
  </section>`;
}
function dispatchPriorityBadge(priority = '') {
  const raw = String(priority || 'normal').toLowerCase();
  const label = raw.includes('urgent') || raw.includes('emergency') ? 'Urgent' : raw.includes('high') ? 'High' : raw.includes('medium') ? 'New' : 'Normal';
  const cls = raw.includes('urgent') || raw.includes('emergency') || raw.includes('high') ? 'urgent' : raw.includes('medium') ? 'new' : 'normal';
  return `<span class="dispatch-priority-badge ${esc(cls)}">${esc(label)}</span>`;
}
function dispatchDistanceLabel(req = {}) {
  const distance = req.distance_miles || req.distance || req.eta_distance_miles || '';
  if (distance) return `${Number(distance).toFixed ? Number(distance).toFixed(1) : distance} mi`;
  return '—';
}
function dispatchAssignCard(req = {}) {
  const guards = dispatchMapOnlineGuards().map(entry => entry.guard);
  const guardOptions = guards.map(g => `<option value="${esc(g.id)}">${esc(adminGuardOptionLabel(g))}</option>`).join('');
  return `<article class="dispatch-assign-card">
    <div class="dispatch-assign-top">${dispatchPriorityBadge(req.priority)}<small>${esc(timeAgo(req.created_at))}</small></div>
    <h3>${esc(requestTitle(req))}</h3>
    <p>${esc(propertyAddress(req))}</p>
    <div class="dispatch-assign-meta"><span>• ${esc(statusText(req.priority || 'Normal'))}</span><span>⌖ ${esc(dispatchDistanceLabel(req))}</span></div>
    <div class="dispatch-assign-actions">
      <select data-assign-guard="${esc(req.id)}">${guardOptions || '<option value="">No online guards</option>'}</select>
      <button type="button" data-action="admin-assign-now" data-request-id="${esc(req.id)}" ${guards.length ? '' : 'disabled'}>Assign</button>
      <button type="button" data-view="pending-dispatch">⋮</button>
    </div>
  </article>`;
}
