    { key:'agency_accepted', label:'Agency Accepted', client:'A licensed agency accepted your patrol request.', icon:'✓' },
    { key:'guard_assigned', label:'Guard Assigned', client:'The agency assigned a guard to your job.', icon:'◎' },
    { key:'guard_accepted', label:'Guard Accepted', client:'The guard accepted the assignment.', icon:'●' },
    { key:'en_route', label:'En Route', client:'Your guard is heading to the property.', icon:'➤' },
    { key:'arrived', label:'Arrived', client:'Your guard arrived at the property.', icon:'⌖' },
    { key:'in_progress', label:'Checking Property', client:'The property check is underway.', icon:'▦' },
    { key:'proof_uploaded', label:'Proof Uploaded', client:'Photo/video proof has been uploaded for review.', icon:'⬆' },
    { key:'completed', label:'Completed', client:'The patrol job has been completed.', icon:'✓' },
    { key:'report_published', label:'Report Published', client:'Your final report is ready in the Reports page.', icon:'▣' }
