    if (!raw || ['pending','requested','new','pending_dispatch','client_request','marketplace_open','pending_marketplace','open'].includes(raw)) return 'open_marketplace';
    if (['agency_accepted','accepted_by_agency','claimed','agency_claimed'].includes(raw)) return 'agency_accepted';
    if (['guard_assigned','assigned','dispatch_assigned','agency_assigned_guard'].includes(raw)) return 'guard_assigned';
    if (['guard_accepted','accepted','guard_accepted_job'].includes(raw)) return 'guard_accepted';
    if (['en_route','on_way','on_the_way','route_started'].includes(raw)) return 'en_route';
    if (['arrived','on_site','onsite'].includes(raw)) return 'arrived';
    if (['in_progress','active','checking','checking_property','started_patrol','patrol_started'].includes(raw)) return 'in_progress';
    if (['proof_uploaded','proof','uploaded_proof','proof_submitted'].includes(raw)) return 'proof_uploaded';
    if (['completed','complete','finished','closed'].includes(raw)) return 'completed';
    if (['report_published','published','final_report_published','released','report_released'].includes(raw)) return 'report_published';
