    if (/report.*publish|publish.*report|released/.test(text)) return 'report_published';
    if (/proof|upload/.test(text)) return 'proof_uploaded';
    if (/complete|finish|closed/.test(text)) return 'completed';
    if (/checking|started|progress|patrol/.test(text)) return 'in_progress';
    if (/arriv|on site|onsite/.test(text)) return 'arrived';
    if (/route|way/.test(text)) return 'en_route';
    if (/guard.*accept|accept.*guard/.test(text)) return 'guard_accepted';
