      marketplace_job_id: linked.id || req.marketplace_job_id || req.job_id || '',
      patrol_request_id: linked.patrol_request_id || req.id || '',
      job_number: linked.job_number || req.job_number || req.request_number || `REQ-${String(req.id || '').slice(0,8)}`,
      client_id: linked.client_id || req.client_id || '',
      property_id: linked.property_id || req.property_id || '',
      property_label: linked.property_label || req.property_name || req.property_label || '',
      property_address: linked.property_address || req.property_address || req.address || '',
      current_status: status,
