/* ============================================================
   v4.0.34 SIDEBAR NAV STACK FIX
   Fixes Settings > Profile Photo preview-only behavior by saving
   uploaded device photos to Supabase Storage and persisting avatar_url
   through cp_update_my_profile. Keeps v4.0.19 quiet admin sync and
   v4.0.20 client tracker intact.
   ============================================================ */
(() => {
  const CP421_VERSION = '4.0.32';
  const CP421_LABEL = 'v4.0.34 SIDEBAR NAV STACK FIX';
  const CP421_SLUG = '4.0.32-compact-company-card-logo-map-header-cleanup';
  const CP421_CACHE = '2026-06-27T2215-v432-company-card-logo-map-header-cleanup';
  let cp421SelectedProfilePhotoFile = null;
  let cp421ObjectUrl = '';

  function cp421LockBadge() {
    try {
      BUILD.version = CP421_VERSION;
      BUILD.label = CP421_LABEL;
      window.CP_ACTIVE_BUILD_LABEL = CP421_LABEL;
      window.CP_DEV_CACHE_BUST = CP421_CACHE;
      document.querySelectorAll('.cp-build-badge,.version-mini').forEach(el => { el.textContent = CP421_LABEL; });
      const meta = document.querySelector('meta[name="app-version"]');
      if (meta) meta.setAttribute('content', CP421_SLUG);
      if (typeof ensureBadge === 'function') ensureBadge();
    } catch {}
  }

  function cp421RoleLabel() {
    return typeof roleLabel === 'function' ? roleLabel(state.role) : (state.role || 'User');
  }
  function cp421CurrentProfileName() {
    if (typeof settingsProfileName === 'function') return settingsProfileName();
    return state.profile?.display_name || state.profile?.name || state.profile?.email || cp421RoleLabel();
  }
  function cp421CurrentEmail() {
    if (typeof settingsProfileEmail === 'function') return settingsProfileEmail();
    return state.profile?.email || '';
  }
  function cp421CurrentPhone() {
    if (typeof settingsPhone === 'function') return settingsPhone();
    return state.profile?.phone || state.profile?.phone_number || '';
  }
  function cp421CurrentPhoto() {
    if (typeof settingsPhotoUrl === 'function') return settingsPhotoUrl();
    return state.profile?.avatar_url || state.profile?.photo_url || state.profile?.profile_photo_url || '';
  }
  function cp421Initials(value = '') {
    return typeof initials === 'function' ? initials(value) : String(value || 'U').slice(0, 2).toUpperCase();
  }
  function cp421Esc(value = '') {
    return typeof esc === 'function' ? esc(value) : String(value ?? '').replace(/[&<>"']/g, ch => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch]));
  }

  if (typeof settingsPhotoUrl === 'function') {
    settingsPhotoUrl = function cp421SettingsPhotoUrl() {
      return state.profile?.avatar_url || state.profile?.profile_avatar_url || state.profile?.photo_url || state.profile?.profile_photo_url || getGuardPhotoUrl?.() || '';
    };
  }

  if (typeof settingsProfileContent === 'function' && !window.CP421_PROFILE_CONTENT_PATCHED) {
    window.CP421_PROFILE_CONTENT_PATCHED = true;
    settingsProfileContent = function cp421SettingsProfileContent() {
      const photo = cp421CurrentPhoto();
      const name = cp421CurrentProfileName();
      const title = state.profile?.job_title || (state.role === 'client' ? 'Property Manager' : cp421RoleLabel());
      return `<div class="settings-main-stack cp421-settings-profile-stack">
        <section class="panel panel-pad settings-profile-card cp421-settings-profile-card">
          <div class="settings-section-head"><div><h2>Profile Information</h2><p>Update your name, contact info, and saved profile photo.</p></div><button class="primary-button" data-action="save-settings">Save Changes</button></div>
          <div class="settings-profile-grid">
            <div class="settings-form-grid">
              <label>Full Name<input type="text" data-settings-profile-name name="display_name" value="${cp421Esc(name)}" placeholder="Full name"></label>
              <label>Job Title<input type="text" data-settings-profile-title name="job_title" value="${cp421Esc(title)}" placeholder="Job title"></label>
              <label>Email Address<input type="email" data-settings-profile-email name="email" value="${cp421Esc(cp421CurrentEmail())}" placeholder="email@example.com" readonly></label>
              <label>Preferred Contact Method<select data-settings-contact-method><option>Email</option><option>SMS</option><option>Phone</option></select></label>
              <label>Phone Number<input type="tel" data-settings-profile-phone name="phone" value="${cp421Esc(cp421CurrentPhone())}" placeholder="Phone number"></label>
              <label>Secondary Phone (Optional)<input type="tel" value="" placeholder="Optional secondary phone"></label>
              <label>Time Zone<select><option>(GMT-07:00) Pacific Time (US & Canada)</option><option>(GMT-08:00) Alaska</option><option>(GMT-06:00) Mountain Time</option><option>(GMT-05:00) Central Time</option><option>(GMT-04:00) Eastern Time</option></select></label>
              <label>Language<select><option>English (US)</option><option>Spanish</option></select></label>
            </div>
            <aside class="settings-photo-panel cp421-photo-panel">
              <p>Profile Photo</p>
              <div class="settings-avatar" data-settings-photo-preview>${photo ? `<img src="${cp421Esc(photo)}" alt="${cp421Esc(name)}">` : `<span>${cp421Esc(cp421Initials(name))}</span>`}<em>📷</em></div>
              <label class="settings-upload-button"><input type="file" accept="image/jpeg,image/jpg,image/png,image/webp,image/gif" data-settings-photo-file><strong>Upload Photo</strong></label>
              <small data-profile-photo-save-status>JPG, PNG, WEBP, GIF up to 8MB. Click Save Changes after choosing.</small>
            </aside>
          </div>
        </section>
        <section class="panel panel-pad settings-password-card">
          <div class="settings-section-head"><div><h2>Change Password</h2><p>Ensure your account is using a strong password.</p></div></div>
          <div class="settings-password-grid"><label>Current Password<div><input type="password" placeholder="Enter current password"><span>⊙</span></div></label><label>New Password<div><input type="password" placeholder="Enter new password"><span>⊙</span></div></label><label>Confirm New Password<div><input type="password" placeholder="Confirm new password"><span>⊙</span></div></label><button class="primary-button" data-action="update-settings-password">Update Password</button></div>
        </section>
        <section class="panel panel-pad settings-comm-card">
          <div class="settings-section-head"><div><h2>Communication Preferences</h2><p>Choose what updates and alerts you want to receive.</p></div></div>
          <div class="settings-pref-grid">
            ${settingsPrefCard?.('♧','Patrol Updates','Receive updates when a patrol is started, completed, or canceled.', true) || ''}
            ${settingsPrefCard?.('✉','Report Notifications','Get notified when new reports are ready to view.', true) || ''}
            ${settingsPrefCard?.('☵','Message Alerts','Receive alerts for new messages from dispatch.', true) || ''}
            ${settingsPrefCard?.('⚠','Security Alerts','Important security alerts and incident notifications.', false) || ''}
            ${settingsPrefCard?.('▦','Scheduled Reminders','Reminders for upcoming patrols and schedules.', true) || ''}
            ${settingsPrefCard?.('📣','Marketing & News','Product updates, tips, and promotional offers.', false) || ''}
          </div>
        </section>
      </div>`;
    };
  }

  function cp421SetPhotoStatus(message = '') {
    const el = document.querySelector('[data-profile-photo-save-status]');
    if (el && message) el.textContent = message;
  }
  function cp421ValidatePhoto(file) {
    if (!file) return '';
    if (!String(file.type || '').startsWith('image/')) throw new Error('Profile photo must be an image file.');
    if (Number(file.size || 0) > 8388608) throw new Error('Profile photo must be 8MB or smaller.');
    return file;
  }
  function cp421SafeFileName(file) {
    const ext = (String(file?.name || 'profile-photo').split('.').pop() || 'jpg').toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 8) || 'jpg';
    const base = String(file?.name || 'profile-photo').replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9._-]/g, '_').slice(0, 58) || 'profile-photo';
    return `${base}.${ext}`;
  }
  function cp421ProfileObjectPath(file) {
    const rawId = state.profile?.auth_user_id || state.profile?.id || state.profile?.email || 'profile';
    const safeId = String(rawId || 'profile').replace(/[^a-zA-Z0-9._-]/g, '_');
    return `${safeId}/${Date.now()}-${Math.random().toString(16).slice(2)}-${cp421SafeFileName(file)}`;
  }
  async function cp421UploadProfilePhoto(file) {
    cp421ValidatePhoto(file);
    const objectPath = cp421ProfileObjectPath(file);
    await supabase.uploadStorageObject('profile-photos', objectPath, file, { upsert: false });
    return supabase.getPublicUrl('profile-photos', objectPath);
  }
  function cp421ProfilePayload(avatarUrl = '') {
    const nameInput = document.querySelector('[data-settings-profile-name]');
    const phoneInput = document.querySelector('[data-settings-profile-phone]');
    const titleInput = document.querySelector('[data-settings-profile-title]');
    const displayName = String(nameInput?.value || cp421CurrentProfileName() || '').trim();
    const phone = String(phoneInput?.value || cp421CurrentPhone() || '').trim();
    const title = String(titleInput?.value || '').trim();
    return {
      p_display_name: displayName || cp421CurrentProfileName(),
      p_avatar_url: avatarUrl || cp421CurrentPhoto(),
      _phone: phone,
      _job_title: title
    };
  }
  function cp421PatchLocalProfile(payload = {}, avatarUrl = '') {
    const url = avatarUrl || payload.p_avatar_url || cp421CurrentPhoto();
    state.profile = {
      ...(state.profile || {}),
      display_name: payload.p_display_name || state.profile?.display_name || '',
      name: payload.p_display_name || state.profile?.name || '',
      phone: payload._phone || state.profile?.phone || '',
      phone_number: payload._phone || state.profile?.phone_number || '',
      job_title: payload._job_title || state.profile?.job_title || '',
      avatar_url: url,
      profile_avatar_url: url,
      photo_url: url,
      profile_photo_url: url,
      updated_at: new Date().toISOString()
    };
    const email = String(state.profile?.email || '').toLowerCase();
    const guardId = String(state.profile?.guard_id || '');
    const clientId = String(state.profile?.client_id || '');
    (state.guards || []).forEach(g => {
      if ((guardId && String(g.id || '') === guardId) || (email && String(g.email || '').toLowerCase() === email)) {
        g.name = state.profile.display_name || g.name;
        g.display_name = state.profile.display_name || g.display_name;
        g.avatar_url = url;
        g.photo_url = g.photo_url || url;
        g.profile_avatar_url = url;
      }
    });
    (state.clients || []).forEach(c => {
      if ((clientId && String(c.id || '') === clientId) || (email && String(c.email || '').toLowerCase() === email)) {
        c.name = state.profile.display_name || c.name;
        c.display_name = state.profile.display_name || c.display_name;
        c.avatar_url = url;
        c.logo_url = c.logo_url || url;
        c.profile_avatar_url = url;
      }
    });
  }
  async function cp421PersistProfile(payload = {}) {
    try {
      const result = await supabase.rpc('cp_update_my_profile', {
        p_display_name: payload.p_display_name,
        p_avatar_url: payload.p_avatar_url
      });
      if (result?.profile) state.profile = { ...(state.profile || {}), ...result.profile };
      return result;
    } catch (err) {
      const msg = String(err?.message || err || '');
      if (/function.*cp_update_my_profile|Could not find the function|schema cache|avatar_url|profile-photos|bucket/i.test(msg)) {
        throw new Error(`${msg} Run the consolidated SQL only if this Supabase project is missing the profile photo bucket/RPC.`);
      }
      throw err;
    }
  }
  async function cp421SaveProfile(button = null) {
    const fileInput = document.querySelector('[data-settings-photo-file]');
    const file = cp421SelectedProfilePhotoFile || fileInput?.files?.[0] || null;
    let avatarUrl = cp421CurrentPhoto();
    if (button && typeof setActionButtonBusy === 'function') setActionButtonBusy(button, file ? 'Uploading...' : 'Saving...');
    cp421SetPhotoStatus(file ? 'Uploading profile photo…' : 'Saving profile…');
    if (file) avatarUrl = await cp421UploadProfilePhoto(file);
    const payload = cp421ProfilePayload(avatarUrl);
    cp421SetPhotoStatus('Saving profile record…');
    const result = await cp421PersistProfile(payload);
    cp421PatchLocalProfile(payload, result?.profile?.avatar_url || avatarUrl);
    cp421SelectedProfilePhotoFile = null;
    if (fileInput) fileInput.value = '';
    cp421SetPhotoStatus('Profile photo saved.');
    try { await loadData(); } catch {}
    render();
    cp421LockBadge();
    toast('Profile photo saved.', 'success');
  }

  document.addEventListener('change', e => {
    const input = e.target?.closest?.('input[data-settings-photo-file]');
    if (!input) return;
    const file = input.files?.[0];
    if (!file) return;
    try {
      cp421ValidatePhoto(file);
      cp421SelectedProfilePhotoFile = file;
      if (cp421ObjectUrl) URL.revokeObjectURL(cp421ObjectUrl);
      cp421ObjectUrl = URL.createObjectURL(file);
      const preview = document.querySelector('[data-settings-photo-preview]');
      if (preview) preview.innerHTML = `<img src="${cp421Esc(cp421ObjectUrl)}" alt="Profile photo preview"><em>📷</em>`;
      cp421SetPhotoStatus('Photo selected. Click Save Changes to save it to your profile.');
    } catch (err) {
      input.value = '';
      cp421SelectedProfilePhotoFile = null;
      toast(friendly?.(err) || err.message || 'Profile photo failed validation.');
    }
  }, true);

  document.addEventListener('click', async e => {
    const button = e.target?.closest?.('button[data-action="save-settings"]');
    if (!button) return;
    if ((state.settingsTab || 'profile') !== 'profile') return;
    e.preventDefault();
    e.stopImmediatePropagation();
    if (button.disabled || button.dataset.busy === '1') return;
    try { await cp421SaveProfile(button); }
    catch (err) {
      cp421SetPhotoStatus('Profile photo did not save.');
      toast(friendly?.(err) || err.message || 'Profile photo save failed.');
    }
    finally { if (document.body.contains(button) && typeof clearActionButtonBusy === 'function') clearActionButtonBusy(button); }
  }, true);

  window.CP421_PROFILE_PHOTO_SAVE_FIX = { uploadProfilePhoto: cp421UploadProfilePhoto, saveProfile: cp421SaveProfile, lockBadge: cp421LockBadge };
  cp421LockBadge();
  setTimeout(cp421LockBadge, 0);
  setTimeout(cp421LockBadge, 300);
  setTimeout(cp421LockBadge, 1000);
  setInterval(cp421LockBadge, 2500);
})();


