  function cp432AgencyIdFromJob(j = {}){ return String(j.accepted_agency_id || j.agency_id || j.company_id || j.assigned_agency_id || '').trim(); }
  function cp432CompanyRows(){
    cp432MirrorActiveAgencyLogo();
    const agencies = (typeof cp409ApprovedAgencies === 'function' ? cp409ApprovedAgencies() : (state.agencies || [])).length ? (typeof cp409ApprovedAgencies === 'function' ? cp409ApprovedAgencies() : (state.agencies || [])) : (state.agencies || []);
    const guards = state.guards || [];
    const jobs = typeof marketplaceJobRows === 'function' ? marketplaceJobRows() : (state.marketplaceJobs || []);
    return agencies.map(agency => {
      const id = cp432AgencyId(agency);
      const rowGuards = id ? guards.filter(g => cp432AgencyIdFromGuard(g) === id) : [];
      const rowJobs = id ? jobs.filter(j => cp432AgencyIdFromJob(j) === id) : [];
      const onlineCount = rowGuards.filter(g => /online|active|gps/i.test(String(g.status || g.duty_status || g.online_status || '')) || Boolean(g.is_online || g.online)).length;
      return { agency, guards: rowGuards, jobs: rowJobs, onlineCount };
    });
  }
  function cp432AgencyLogoBlock(agency = {}){
    const name = cp432AgencyName(agency);
    const logo = cp432AgencyLogo(agency);
    return `<div class="cp432-company-logo-col"><div class="cp432-company-logo-frame">${logo ? `<img src="${cp432Esc(logo)}" alt="${cp432Esc(name)} logo" loading="lazy" />` : `<span>${cp432Esc(cp432Initials(name))}</span>`}</div></div>`;
  }
  function cp432CompanyActivityCard(row = {}){
    const agency = row.agency || {};
    const jobs = row.jobs || [];
    const name = cp432AgencyName(agency);
    return `<article class="cp432-company-card">
      ${cp432AgencyLogoBlock(agency)}
      <div class="cp432-company-main">
        <div class="cp432-company-top"><strong>${cp432Esc(name)}</strong><em>Licensed</em></div>
        <div class="cp432-company-grid">
          <span>Online guards <b>${cp432Esc(row.onlineCount || 0)}</b></span>
          <span>Total guards <b>${cp432Esc((row.guards || []).length || 0)}</b></span>
          <span class="motion">Jobs in motion <b>${cp432Esc(jobs.filter(cp432InMotion).length)}</b></span>
          <span class="done">Jobs completed <b>${cp432Esc(jobs.filter(cp432Done).length || agency.completed_jobs_count || 0)}</b></span>
        </div>
      </div>
    </article>`;
  }
  if (typeof cp409CompanySummaryPanel === 'function') {
    cp409CompanySummaryPanel = function cp432CompanySummaryPanel(){
      const rows = cp432CompanyRows().slice(0, 8);
      return `<section class="panel panel-pad cp432-company-panel"><div class="panel-head cp432-company-head"><div><h2>Company Activity</h2><p>Real-time activity and operational overview for licensed companies active on the marketplace.</p></div><button class="ghost-button" data-view="agency-approvals">Agencies</button></div><div class="cp432-company-list">${rows.length ? rows.map(cp432CompanyActivityCard).join('') : '<div class="empty">No approved agencies yet.</div>'}</div></section>`;
    };
  }

  // Remove the left highlighted paragraph from the map header. The map should use
  // filters + map, not a block of explanatory copy in the header area.
  if (typeof cp409PlatformMapPanel === 'function' && !window.CP432_MAP_HEADER_CLEANED) {
    window.CP432_MAP_HEADER_CLEANED = true;
    const baseMapPanel = cp409PlatformMapPanel;
    cp409PlatformMapPanel = function cp432PlatformMapPanel(){
      return String(baseMapPanel())
        .replace(/<p>Platform Admin sees every mapped client property and every mapped guard record\. Route lines only appear for active movement jobs\.<\/p>/i, '')
        .replace(/<p>Same live map system as the guard, client, and agency GPS views[^<]*<\/p>/i, '')
        .replace(/<p>[^<]*(?:mapped client property|mapped guard record|active movement jobs)[^<]*<\/p>/i, '');
    };
  }

  function cp432GuardKeys(g = {}){ return [g.id,g.auth_user_id,g.user_id,g.profile_id,g.email].filter(Boolean).map(v => String(v).trim().toLowerCase()); }
  function cp432JobGuardKeys(j = {}){ return [j.assigned_guard_id,j.guard_id,j.assigned_guard_auth_user_id,j.guard_auth_user_id,j.assigned_guard_email,j.guard_email].filter(Boolean).map(v => String(v).trim().toLowerCase()); }
  function cp432FindGuardForJob(job = {}){ const keys = cp432JobGuardKeys(job); return (state.guards || []).find(g => cp432GuardKeys(g).some(k => keys.includes(k))) || {}; }
  function cp432FindAgencyById(id = ''){ const key = String(id || '').trim(); return (state.agencies || []).find(a => cp432AgencyKeys(a).includes(key.toLowerCase())) || {}; }
  function cp432CompanyName(job = {}, guard = {}){
    const agency = cp432FindAgencyById(cp432AgencyIdFromGuard(guard) || cp432AgencyIdFromJob(job));
    return cp432First(guard.company_name, guard.agency_name, job.agency_name, job.accepted_agency_name, job.company_name, cp432AgencyName(agency), 'Co Pilot Security Marketplace');
  }
  function cp432GuardName(job = {}, guard = {}){ return cp432First(guard.name, guard.display_name, guard.full_name, guard.email, job.assigned_guard_name, job.guard_name, job.assigned_guard_email, 'Guard'); }
  function cp432GuardPhoto(guard = {}, job = {}){ return cp432First(guard.photo_url, guard.avatar_url, guard.image_url, guard.profile_photo_url, guard.picture_url, guard.headshot_url, guard.user_photo_url, guard.profile_avatar_url, job.guard_photo_url, job.assigned_guard_photo_url, job.guard_avatar_url, job.assigned_guard_avatar_url); }
  function cp432CoordsLabel(coords = null){ return coords && Number.isFinite(Number(coords.lat)) && Number.isFinite(Number(coords.lng)) ? `${Number(coords.lat).toFixed(5)}, ${Number(coords.lng).toFixed(5)}` : ''; }
  function cp432GuardAddress(entry = {}){ const g = entry.guard || {}; return cp432First(entry.currentAddress, g.current_address, g.last_address, g.location_address, g.address, g.gps_address, typeof dispatchGuardGpsAddress === 'function' ? dispatchGuardGpsAddress(entry) : '', cp432CoordsLabel(entry.coords), 'Current address unavailable'); }
  function cp432RouteAllowed(job = {}){ try { if (window.CP426_GLOBAL_JOB_STATE_MAP_FLOW?.showRoute) return Boolean(window.CP426_GLOBAL_JOB_STATE_MAP_FLOW.showRoute(job)); } catch {} const s = cp432Status(job); return ['guard_accepted','accepted','en_route','on_the_way','on_way'].includes(s); }
  function cp432PropertyById(id = ''){ const key = String(id || '').trim(); return (state.properties || []).find(p => String(p.id || p.property_id || '') === key) || {}; }
  function cp432PropertyFromJob(job = {}){ const found = cp432PropertyById(job.property_id || job.client_property_id); if (Object.keys(found).length) return found; return { id: job.property_id || job.id || '', name: job.property_name || job.property_label || job.label || 'Property', label: job.property_label || job.property_name || job.label || 'Property', address: job.property_address || job.service_address || job.address || '', city: job.property_city || job.city || '', state: job.property_state || job.state || '', zip_code: job.property_zip || job.zip || '', owner_name: job.client_name || job.client_email || 'Client', photo_url: job.property_photo_url || job.reference_photo_url || job.client_reference_photo_url || job.concern_photo_url || '' }; }
  function cp432ClientName(job = {}, property = {}){ return cp432First(job.client_name, job.client_label, job.owner_name, job.client_email, property.client_name, property.owner_name, property.contact_name, property.client_email, 'Client'); }
  function cp432PropertyName(job = {}, property = {}){ return cp432First(job.property_label, job.property_name, job.label, property.label, property.name, property.property_name, 'Property'); }
  function cp432PropertyAddress(job = {}, property = {}){ const propAddr = [property.address || property.address_line1, property.city, property.state, property.zip_code || property.zip].filter(Boolean).join(', '); return cp432First(job.property_address, job.service_address, job.address, propAddr, typeof propertyDisplayAddress === 'function' ? propertyDisplayAddress(property) : '', 'Address unavailable'); }
